#include <iostream>
#include <queue>
#include <vector>
using namespace std;

void bfs(int start, vector<int> adj[], int V) {
    vector<bool> visited(V, false);
    queue<int> q;
    q.push(start);
    visited[start] = true;

    while(!q.empty()) {
        int node = q.front(); q.pop();
        cout << node << " ";
        for(int neigh : adj[node]) {
            if(!visited[neigh]) {
                visited[neigh] = true;
                q.push(neigh);
            }
        }
    }
}

#include <iostream>
#include <vector>
using namespace std;

void dfs(int node, vector<int> adj[], vector<bool>& visited) {
    visited[node] = true;
    cout << node << " ";
    for(int neigh : adj[node]) {
        if(!visited[neigh])
            dfs(neigh, adj, visited);
    }
}
